Aero.contentlist=new Vue({el:"#contentlist",data:{loading:!0,group:null,items:[],types:[]},methods:{bind:function(e){this.group=e.group,this.types=e.types,this.items=e.items.map(function(t){var n=e.types.find(function(e){return e.id===t.typeId});return t.type=n.title||t.typeId,t})},load:function(e){var t=this;Aero.permissions.load(function(){fetch(Aero.baseUrl+"manager/api/content/"+e+"/list").then(function(e){return e.json()}).then(function(e){t.bind(e),t.loading=!1}).catch(function(e){console.log("error:",e)})})},remove:function(e){var t=this;Aero.alert.open({title:Aero.resources.texts.delete,body:Aero.resources.texts.deletePageConfirm,confirmCss:"btn-danger",confirmIcon:"fas fa-trash",confirmText:Aero.resources.texts.delete,onConfirm:function(){fetch(Aero.baseUrl+"manager/api/content/delete",{method:"delete",headers:Aero.utils.antiForgeryHeaders(),body:JSON.stringify(e)}).then(function(e){return e.json()}).then(function(e){Aero.notifications.push(e),t.load(t.group.id)}).catch(function(e){console.log("error:",e)})}})}},created:function(){}});